-- ============================================================
-- MIGRACIÓN COMPLETA: db_romo  |  SQL Server → PostgreSQL
-- ============================================================
-- EJECUCIÓN:
--   1. CREATE DATABASE db_romo WITH ENCODING='UTF8';
--   2. \c db_romo
--   3. psql -d db_romo -f migration_db_romo_final.sql
-- ============================================================
--
-- CLASIFICACIÓN DE SPs:
--   PROCEDURE (con COMMIT/ROLLBACK + INOUT escalares):
--     sp_AsignarServicio, sp_CancelarReserva, sp_CreateReserva,
--     sp_ReprogramarReserva, sp_ValidarHorario, sp_DeleteTimerReserva
--
--   FUNCTION (retorna filas, sin transacción):
--     fn_ListClientes, fn_ListHorariosDisponibles,
--     fn_ListHorariosReprogramacion, fn_ListReservas,
--     fn_LoginUsuario, fn_ParametroOperativo,
--     fn_SugerirAsignacion_Gruas, fn_SugerirAsignacion_Operadores,
--     fn_TarifarioGlobal
--
-- MAPA DE TIPOS:
--   DATETIME2(7)     → TIMESTAMP(6)
--   TIME(7)          → TIME(6)
--   NVARCHAR(MAX)    → TEXT
--   INT IDENTITY     → INT GENERATED ALWAYS AS IDENTITY
--   getdate()        → NOW()
--   ISNULL(a,b)      → COALESCE(a,b)
--   SCOPE_IDENTITY() → RETURNING "Id" INTO variable
--   ERROR_MESSAGE()  → SQLERRM
-- ============================================================

BEGIN;


-- ============================================================
-- SECCIÓN 2: TIPO COMPUESTO  (UserDefinedTableType)
-- ============================================================
-- [CAMBIO] No existe TVP en PostgreSQL.
-- Se reemplaza por TYPE compuesto + ARRAY en sp_CreateReserva.
-- Llamada desde app: ARRAY[ROW('Camion','ABC','Mod','Obs')::tipo_vehiculo_detalle]
CREATE TYPE tipo_vehiculo_detalle AS (
    "Tipo"        VARCHAR(100),
    "Placa"       VARCHAR(10),
    "Descripcion" VARCHAR(200),
    "Observacion" VARCHAR(100)
);


-- ============================================================
-- SECCIÓN 3: TABLAS
-- ============================================================
-- Orden respeta dependencias FK:
-- Usuario → Cliente, Operador
-- Grua    → BitacoraMantenimiento, Reserva, TimerReserva
-- Cliente → Reserva, TimerReserva
-- Operador → Disponibilidad, Reserva, TimerReserva
-- Reserva → Vehiculo
-- TimerReserva → TimerVehiculo

CREATE TABLE "Usuario" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "Alias"              VARCHAR(10)   NOT NULL,
    "Contraseña"         VARCHAR(100)  NOT NULL,
    "Correo"             VARCHAR(100)  NOT NULL,
    "Nombres"            VARCHAR(100)  NOT NULL,
    "Apellidos"          VARCHAR(100)  NOT NULL,
    "Rol"                VARCHAR(100)  NOT NULL DEFAULT 'CLIENTE',
    "Estado"             VARCHAR(20)   NOT NULL DEFAULT 'ACTIVO',
    "Telefono"           VARCHAR(50)   NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    CONSTRAINT pk_Usuario     PRIMARY KEY ("Id"),
    CONSTRAINT CK_Usuario_Estado CHECK ("Estado" IN ('ACTIVO','INACTIVO')),
    CONSTRAINT CK_Usuario_Rol   CHECK ("Rol"    IN ('ADMINISTRADOR','STAFF','CLIENTE','OPERADOR'))
);
COMMENT ON COLUMN "Usuario"."Rol" IS 'Rol=''Administador'',''Staff'',''Cliente'',''Operador''';

CREATE TABLE "Grua" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "Placa"              VARCHAR(10)   NOT NULL,
    "Marca"              VARCHAR(30)   NOT NULL,
    "Modelo"             VARCHAR(30)   NOT NULL,
    "Capacidad"          SMALLINT      NOT NULL,
    "FecVenSeg"          DATE          NOT NULL,
    "Estado"             VARCHAR(20)   NOT NULL DEFAULT 'ACTIVO',
    "EstadoOperacion"    VARCHAR(20)   NOT NULL DEFAULT 'OPERATIVA',
    "AñoFabricacion"     SMALLINT      NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    CONSTRAINT pk_GRUA                 PRIMARY KEY ("Id"),
    CONSTRAINT CK_Grua_Estado          CHECK ("Estado"          IN ('ACTIVO','INACTIVO')),
    CONSTRAINT CK_Grua_EstadoOperacion CHECK ("EstadoOperacion" IN ('OPERATIVA','ENTALLER'))
);
COMMENT ON TABLE  "Grua"                   IS 'EstadoOperacion: ''operativa'',''entaller''';
COMMENT ON COLUMN "Grua"."EstadoOperacion" IS 'EstadoOperacion: ''operativa'',''entaller''';

CREATE TABLE "Cliente" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "Empresa"            VARCHAR(100)  NOT NULL,
    "NomContacto"        VARCHAR(100)  NOT NULL,
    "NroContacto"        VARCHAR(20)   NOT NULL,
    "CorreoContacto"     VARCHAR(100)  NOT NULL,
    "TarifaBase"         DECIMAL(10,2) NOT NULL,
    "TarifaKm"           DECIMAL(10,2) NOT NULL,
    "Estado"             VARCHAR(20)   NOT NULL DEFAULT 'ACTIVO',
    "IdUsuario"          INT           NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    CONSTRAINT pk_Cliente            PRIMARY KEY ("Id"),
    CONSTRAINT unq_Cliente_IdUsuario UNIQUE ("IdUsuario"),
    CONSTRAINT CK_Cliente_Estado     CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "Operador" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "NroLicencia"        VARCHAR(9)    NOT NULL,
    "FecVenLic"          DATE          NOT NULL,
    "IdUsuario"          INT           NOT NULL,
    "Estado"             VARCHAR(20)   NOT NULL DEFAULT 'ACTIVO',
    "FechaCreacion"      TIMESTAMP(6)  NULL     DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadorPor"         INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    CONSTRAINT pk_Operador            PRIMARY KEY ("Id"),
    CONSTRAINT unq_Operador_IdUsuario UNIQUE ("IdUsuario"),
    CONSTRAINT CK_Operador_Estado     CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "ConfiguracionHorario" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "NroDia"             SMALLINT      NOT NULL,
    "NombreDia"          VARCHAR(9)    NOT NULL,
    "HoraInicio"         TIME(6)       NOT NULL,
    "HoraFinal"          TIME(6)       NOT NULL,
    "Estado"             VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    "Rol"                VARCHAR(20)   NULL     DEFAULT 'ADMINISTRADOR',
    CONSTRAINT pk_ConfiguracionHorario        PRIMARY KEY ("Id"),
    CONSTRAINT CK_ConfiguracionHorario_Estado CHECK ("Estado" IN ('ACTIVO','INACTIVO')),
    CONSTRAINT CHK_ConfiguracionHorario_Rol   CHECK ("Rol"    IN ('ADMINISTRADOR','STAFF','CLIENTE','OPERADOR'))
);

CREATE TABLE "Disponibilidad" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "NroDia"             SMALLINT      NOT NULL,
    "NombreDia"          VARCHAR(9)    NOT NULL,
    "Estado"             VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    "IdOperador"         INT           NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    "HoraInicio"         TIME(6)       NOT NULL,
    "HoraFin"            TIME(6)       NOT NULL,
    CONSTRAINT pk_Disponibilidad      PRIMARY KEY ("Id"),
    CONSTRAINT CK_Disponibilidad_Estado CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "Excepcion" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "Fecha"              DATE          NOT NULL,
    "Motivo"             VARCHAR(50)   NOT NULL,
    "TiempoInicio"       TIME(6)       NOT NULL,
    "TiempoFinal"        TIME(6)       NOT NULL,
    "DescripcionMotivo"  VARCHAR(100)  NOT NULL,
    "Estado"             VARCHAR(20)   NOT NULL DEFAULT 'ACTIVO',
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    CONSTRAINT pk_Excepcion       PRIMARY KEY ("Id"),
    CONSTRAINT CK_Excepcion_Estado CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "ParametroOperativo" (
    "Id"                   INT           GENERATED ALWAYS AS IDENTITY,
    "TiempoMargenManiobra" SMALLINT      NOT NULL,
    "TiempoRetornoBase"    SMALLINT      NOT NULL,
    "UmbralLargaDistancia" DECIMAL(10,2) NOT NULL,
    "TiempoTolerancia"     SMALLINT      NOT NULL,
    "FechaCreacion"        TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion"   TIMESTAMP(6)  NULL,
    "CreadoPor"            INT           NOT NULL,
    "ActualizadoPor"       INT           NULL,
    "Estado"               VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    "TiempoCorte"          SMALLINT      NOT NULL,
    "TimerAdministrativo"  SMALLINT      NOT NULL,
    "TimerCliente"         SMALLINT      NOT NULL,
    "ZonaHoraria"          VARCHAR(50)   NOT NULL DEFAULT 'America/Lima',
    "MinutosCerca"         SMALLINT      NOT NULL DEFAULT 15,
    "MinutosMedio"         SMALLINT      NOT NULL DEFAULT 35,
    "CoordLatMaps"         VARCHAR(20)   NOT NULL DEFAULT '',
    "CoordLonMaps"         VARCHAR(20)   NOT NULL DEFAULT '',
    "MetrosCercania"       DECIMAL(10,2) NOT NULL DEFAULT 0,
    CONSTRAINT pk_ParametroOperativo       PRIMARY KEY ("Id"),
    CONSTRAINT CK_ParametroOperativo_Estado CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "TarifarioGlobal" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "TarifaBase"         DECIMAL(10,2) NOT NULL,
    "TarifaKm"           DECIMAL(10,2) NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    "Estado"             VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    CONSTRAINT pk_TarifarioGlobal       PRIMARY KEY ("Id"),
    CONSTRAINT CK_TarifarioGlobal_Estado CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "BitacoraMantenimiento" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "NombreResponsable"  VARCHAR(50)   NOT NULL,
    "Nota"               TEXT          NULL,
    "Kilometraje"        INT           NOT NULL,
    "Estado"             VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    "IdGrua"             INT           NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    CONSTRAINT pk_BitacoraMantenimiento        PRIMARY KEY ("Id"),
    CONSTRAINT unq_BitacoraMantenimiento_IdGrua UNIQUE ("IdGrua"),
    CONSTRAINT CK_BitacoraMantenimiento_Estado  CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "Reserva" (
    "Id"                   INT           GENERATED ALWAYS AS IDENTITY,
    "CantidadCarga"        SMALLINT      NOT NULL,
    "IdCliente"            INT           NOT NULL,
    "DireccionOrigen"      TEXT          NOT NULL,
    "CoordLatOrigen"       VARCHAR(20)   NOT NULL,
    "CoordLonOrigen"       VARCHAR(20)   NOT NULL,
    "DireccionDestino"     TEXT          NOT NULL,
    "CoordLatDestino"      VARCHAR(20)   NOT NULL,
    "CoordLonDestino"      VARCHAR(20)   NOT NULL,
    "DistanciaKm"          DECIMAL(10,2) NOT NULL,
    "TiempoEstimado"       INT           NOT NULL,
    "TiempoManiobra"       INT           NOT NULL,
    "TiempoRetorno"        INT           NOT NULL,
    "NroBloques"           INT           NOT NULL,
    "CostoKm"              DECIMAL(10,2) NOT NULL,
    "CostoBase"            DECIMAL(10,2) NOT NULL,
    "EstadoOperacion"      VARCHAR(50)   NOT NULL DEFAULT 'RESERVADO',
    "Estado"               VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    "EstadoAdministrativo" VARCHAR(50)   NOT NULL DEFAULT 'PENDIENTE',
    "HoraInicio"           TIME(6)       NOT NULL,
    "HoraFin"              TIME(6)       NOT NULL,
    "FechaServicio"        DATE          NOT NULL,
    "IdOperador"           INT           NULL,
    "IdGrua"               INT           NULL,
    "FechaCreacion"        TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion"   TIMESTAMP(6)  NULL,
    "CreadoPor"            INT           NOT NULL,
    "ActualizadoPor"       INT           NULL,
    "TipoHorario"          VARCHAR(50)   NULL,
    "MotivoCancelacion"    VARCHAR(255)  NULL,
    "HoraInicioReal"       TIMESTAMP     NULL,
    "HoraFinReal"          TIMESTAMP     NULL,
    "TiempoReal"           INT           GENERATED ALWAYS AS (
                               CASE WHEN "HoraFinReal" IS NOT NULL AND "HoraInicioReal" IS NOT NULL
                               THEN EXTRACT(EPOCH FROM ("HoraFinReal" - "HoraInicioReal"))::INT / 60
                               ELSE NULL END
                           ) STORED,
    CONSTRAINT pk_Reserva                       PRIMARY KEY ("Id"),
    CONSTRAINT CK_Reserva_Estado                CHECK ("Estado"               IN ('ACTIVO','INACTIVO')),
    CONSTRAINT CK_Reserva_EstadoAdministrativo  CHECK ("EstadoAdministrativo" IN ('PENDIENTE','FACTURADO','PAGADO')),
    CONSTRAINT CK_Reserva_EstadoOperacion       CHECK ("EstadoOperacion"      IN ('RESERVADO','ASIGNADO','ENCURSO','FINALIZADO','CANCELADO'))
);
COMMENT ON COLUMN "Reserva"."EstadoOperacion"      IS 'EstadoOperacion=''Reservado'',''Asignado'',''EnCurso'',''Finalizado'',''Cancelado''';
COMMENT ON COLUMN "Reserva"."EstadoAdministrativo" IS 'EstadoAdministrativo=''Pendiente'',''Facturado'',''Pagado''';

CREATE TABLE "TimerReserva" (
    "Id"                   INT           GENERATED ALWAYS AS IDENTITY,
    "CantidadCarga"        SMALLINT      NOT NULL,
    "IdCliente"            INT           NOT NULL,
    "DireccionOrigen"      TEXT          NOT NULL,
    "CoordLatOrigen"       VARCHAR(20)   NOT NULL,
    "CoordLonOrigen"       VARCHAR(20)   NOT NULL,
    "DireccionDestino"     TEXT          NOT NULL,
    "CoordLatDestino"      VARCHAR(20)   NOT NULL,
    "CoordLonDestino"      VARCHAR(20)   NOT NULL,
    "DistanciaKm"          DECIMAL(10,2) NOT NULL,
    "TiempoEstimado"       INT           NOT NULL,
    "TiempoManiobra"       INT           NOT NULL,
    "TiempoRetorno"        INT           NOT NULL,
    "NroBloques"           INT           NOT NULL,
    "CostoKm"              DECIMAL(10,2) NOT NULL,
    "CostoBase"            DECIMAL(10,2) NOT NULL,
    "EstadoOperacion"      VARCHAR(50)   NOT NULL DEFAULT 'RESERVADO',
    "Estado"               VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    "EstadoAdministrativo" VARCHAR(50)   NOT NULL DEFAULT 'PENDIENTE',
    "HoraInicio"           TIME(6)       NOT NULL,
    "HoraFin"              TIME(6)       NOT NULL,
    "FechaServicio"        DATE          NOT NULL,
    "IdOperador"           INT           NULL,
    "IdGrua"               INT           NULL,
    "FechaCreacion"        TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion"   TIMESTAMP(6)  NULL,
    "CreadoPor"            INT           NOT NULL,
    "ActualizadoPor"       INT           NULL,
    "TimerExpiracion"      SMALLINT      NOT NULL,
    "TipoHorario"          VARCHAR(50)   NOT NULL,
    CONSTRAINT pk_Reserva_0                        PRIMARY KEY ("Id"),
    CONSTRAINT CK_Reserva_Estado_0                 CHECK ("Estado"               IN ('ACTIVO','INACTIVO')),
    CONSTRAINT CK_Reserva_EstadoAdministrativo_0   CHECK ("EstadoAdministrativo" IN ('PENDIENTE','FACTURADO','PAGADO')),
    CONSTRAINT CK_Reserva_EstadoOperacion_0        CHECK ("EstadoOperacion"      IN ('RESERVADO','ASIGNADO','ENCURSO','FINALIZADO','CANCELADO'))
);
COMMENT ON COLUMN "TimerReserva"."EstadoOperacion"      IS 'EstadoOperacion=''Reservado'',''Asignado'',''EnCurso'',''Finalizado'',''Cancelado''';
COMMENT ON COLUMN "TimerReserva"."EstadoAdministrativo" IS 'EstadoAdministrativo=''Pendiente'',''Facturado'',''Pagado''';

CREATE TABLE "TimerVehiculo" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "Tipo"               VARCHAR(100)  NOT NULL,
