    "IdTimerReserva"     INT           NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    "Estado"             VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    CONSTRAINT pk_Vehiculo_0             PRIMARY KEY ("Id"),
    CONSTRAINT unq_Vehiculo_IdReserva_0  UNIQUE ("IdTimerReserva"),
    CONSTRAINT CK_Vehiculo_Estado_0      CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);

CREATE TABLE "Vehiculo" (
    "Id"                 INT           GENERATED ALWAYS AS IDENTITY,
    "Tipo"               VARCHAR(100)  NOT NULL,
    "Marca"              VARCHAR(100)  NULL,
    "Modelo"             VARCHAR(200)  NULL,
    "Placa"              VARCHAR(10)   NULL,
    "Observacion"        VARCHAR(100)  NULL,
    "IdReserva"          INT           NOT NULL,
    "FechaCreacion"      TIMESTAMP(6)  NOT NULL DEFAULT NOW(),
    "FechaActualizacion" TIMESTAMP(6)  NULL,
    "CreadoPor"          INT           NOT NULL,
    "ActualizadoPor"     INT           NULL,
    "Estado"             VARCHAR(10)   NOT NULL DEFAULT 'ACTIVO',
    CONSTRAINT pk_Vehiculo        PRIMARY KEY ("Id"),
    CONSTRAINT CK_Vehiculo_Estado  CHECK ("Estado" IN ('ACTIVO','INACTIVO'))
);


-- ============================================================
-- SECCIÓN 4: FOREIGN KEYS
-- ============================================================
ALTER TABLE "BitacoraMantenimiento"
    ADD CONSTRAINT fk_BitacoraMantenimiento_Grua
        FOREIGN KEY ("IdGrua") REFERENCES "Grua" ("Id");

ALTER TABLE "Cliente"
