        FOREIGN KEY ("IdOperador") REFERENCES "Operador" ("Id");

ALTER TABLE "Operador"
    ADD CONSTRAINT fk_Operador_Usuario
        FOREIGN KEY ("IdUsuario") REFERENCES "Usuario" ("Id");

ALTER TABLE "Reserva"
    ADD CONSTRAINT fk_Reserva_Cliente
        FOREIGN KEY ("IdCliente") REFERENCES "Cliente" ("Id");

ALTER TABLE "Reserva"
    ADD CONSTRAINT fk_Reserva_Grua
        FOREIGN KEY ("IdGrua") REFERENCES "Grua" ("Id");

ALTER TABLE "Reserva"
    ADD CONSTRAINT fk_Reserva_Operador
        FOREIGN KEY ("IdOperador") REFERENCES "Operador" ("Id");

ALTER TABLE "TimerReserva"
    ADD CONSTRAINT fk_Reserva_Cliente_0
        FOREIGN KEY ("IdCliente") REFERENCES "Cliente" ("Id");

ALTER TABLE "TimerReserva"
    ADD CONSTRAINT fk_Reserva_Grua_0
        FOREIGN KEY ("IdGrua") REFERENCES "Grua" ("Id");

ALTER TABLE "TimerReserva"
    ADD CONSTRAINT fk_Reserva_Operador_0
        FOREIGN KEY ("IdOperador") REFERENCES "Operador" ("Id");

-- [NOTA] TimerVehiculo tiene dos FK sobre la misma columna (preservadas del origen)
ALTER TABLE "TimerVehiculo"
    ADD CONSTRAINT "FK_TimerVehiculo_TimerReserva"
        FOREIGN KEY ("IdTimerReserva") REFERENCES "TimerReserva" ("Id")
        ON DELETE CASCADE;

ALTER TABLE "TimerVehiculo"
    ADD CONSTRAINT fk_Vehiculo_0_TimerReserva
        FOREIGN KEY ("IdTimerReserva") REFERENCES "TimerReserva" ("Id");

ALTER TABLE "Vehiculo"
    ADD CONSTRAINT fk_Vehiculo_Reserva
        FOREIGN KEY ("IdReserva") REFERENCES "Reserva" ("Id");


-- ============================================================
-- SECCIÓN 5: ÍNDICES
-- ============================================================
-- [CAMBIO] NONCLUSTERED → CREATE INDEX  (PG no distingue clustered/non-clustered)
-- [PRESERVADO] INCLUDE (...) soportado en PostgreSQL >= v11
-- [ELIMINADO] PAD_INDEX, STATISTICS_NORECOMPUTE, OPTIMIZE_FOR_SEQUENTIAL_KEY, etc.

CREATE INDEX "IX_ConfiguracionHorario_Dia_Estado"
    ON "ConfiguracionHorario" ("NroDia" ASC, "Estado" ASC)
    INCLUDE ("HoraInicio", "HoraFinal");

CREATE INDEX "IX_Excepcion_Fecha_Estado"
    ON "Excepcion" ("Fecha" ASC, "Estado" ASC)
    INCLUDE ("TiempoInicio", "TiempoFinal");

CREATE INDEX "IX_Grua_Estado_Operacion_Capacidad"
    ON "Grua" ("Estado" ASC, "EstadoOperacion" ASC, "Capacidad" ASC);

CREATE INDEX "IX_Reserva_Fecha_Carga_Estado"
    ON "Reserva" ("FechaServicio" ASC, "CantidadCarga" ASC, "EstadoOperacion" ASC)
    INCLUDE ("HoraInicio", "HoraFin");

CREATE INDEX "IX_TimerReserva_Fecha_Carga"
    ON "TimerReserva" ("FechaServicio" ASC, "CantidadCarga" ASC)
    INCLUDE ("HoraInicio", "HoraFin", "TimerExpiracion", "FechaCreacion");


-- ============================================================
-- SECCIÓN 6: PROCEDURES  (con COMMIT / ROLLBACK)
-- ============================================================
-- Llamada desde app:
--   CALL sp_xxx(_p1, _p2, ..., _Exitoso => NULL, _Mensaje => NULL, ...)
-- Resultado via parámetros INOUT.
--
-- MAPA T-SQL → PL/pgSQL aplicado a todos los procedures:
--   BEGIN TRANSACTION        → BEGIN (bloque interno)
--   COMMIT TRANSACTION       → COMMIT
--   ROLLBACK TRANSACTION     → ROLLBACK
--   IF @@TRANCOUNT > 0       → manejado por EXCEPTION
--   BEGIN TRY / BEGIN CATCH  → BEGIN ... EXCEPTION WHEN OTHERS THEN
--   GETDATE()                → NOW()
--   CAST(date+time)          → date + time  (produce TIMESTAMP en PG)
--   DATEADD(HOUR,-n,dt)      → dt - (n||' hours')::INTERVAL
--   CONVERT(VARCHAR,t,108)   → to_char(t,'HH24:MI:SS')
--   FORMAT(t,'HH:mm')        → to_char(t,'HH24:MI')
--   string concat a+b        → a || b
--   CAST(x AS VARCHAR)       → x::TEXT
--   ISNULL(a,b)              → COALESCE(a,b)
--   SCOPE_IDENTITY()         → RETURNING "Id" INTO var
--   ERROR_MESSAGE()          → SQLERRM
--   WITH (UPDLOCK,HOLDLOCK)  → FOR UPDATE
-- ────────────────────────────────────────────────────────────

-- ── sp_DeleteTimerReserva ────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_DeleteTimerReserva(
    _Id        INT,
    INOUT _Exitoso INT     DEFAULT 0,
    INOUT _Mensaje TEXT    DEFAULT ''
)
LANGUAGE plpgsql AS $$
BEGIN
    DELETE FROM "TimerReserva" WHERE "Id" = _Id;

    IF FOUND THEN
        _Exitoso := 1;
        _Mensaje := 'Timer eliminado correctamente.';
    ELSE
        _Exitoso := 0;
        _Mensaje := 'No se encontró el timer con Id ' || _Id || '.';
    END IF;

EXCEPTION WHEN OTHERS THEN
    _Exitoso := 0;
    _Mensaje := SQLERRM;
END;
$$;

-- ── sp_AsignarServicio ───────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_AsignarServicio(
    _IdReserva      INT,
    _IdGrua         INT,
    _IdOperador     INT,
    _ActualizadoPor INT,
    INOUT _Exitoso  INT  DEFAULT 0,
    INOUT _Mensaje  TEXT DEFAULT ''
)
LANGUAGE plpgsql AS $$
DECLARE
    v_FechaServicio   DATE;
    v_HoraInicio      TIME;
    v_HoraFin         TIME;
    v_EstadoOperacion VARCHAR(20);
    v_SlotInicioDT    TIMESTAMP;
    v_TiempoCorte     INT;
    v_NroDia          SMALLINT;
    v_PlacaGrua       VARCHAR(20);
    v_NombresOp       VARCHAR(100);
    v_ApellidosOp     VARCHAR(100);
BEGIN

    LOCK TABLE "Reserva" IN SHARE ROW EXCLUSIVE MODE;

    -- 1. Leer reserva
    SELECT r."FechaServicio", r."HoraInicio", r."HoraFin", r."EstadoOperacion"
    INTO   v_FechaServicio, v_HoraInicio, v_HoraFin, v_EstadoOperacion
    FROM   "Reserva" r
    WHERE  r."Id"     = _IdReserva
      AND  r."Estado" = 'ACTIVO';

    IF v_FechaServicio IS NULL THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'La reserva no existe o no se encuentra activa.';
        RETURN;
    END IF;

    -- 2. Validar EstadoOperacion asignable
    IF v_EstadoOperacion IN ('CANCELADO', 'ENCURSO', 'FINALIZADO') THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'La reserva no puede asignarse porque se encuentra en estado '
                    || v_EstadoOperacion || '.';
        RETURN;
    END IF;

    v_SlotInicioDT := v_FechaServicio + v_HoraInicio;
    v_NroDia       := (EXTRACT(DOW FROM v_FechaServicio)::INT + 1)::SMALLINT;

    -- 3. Validar tiempo de corte
    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" WHERE "Estado" = 'ACTIVO';

    IF v_FechaServicio = CURRENT_DATE
       AND v_SlotInicioDT - (v_TiempoCorte || ' hours')::INTERVAL <= NOW()
    THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'No es posible asignar el servicio de las ' ||
                    to_char(v_HoraInicio,'HH24:MI:SS') ||
                    ', debe asignarse con ' || v_TiempoCorte::TEXT ||
                    ' horas de anticipación.';
        RETURN;
    END IF;

    -- 4. Leer operador
    SELECT u."Nombres", u."Apellidos"
    INTO   v_NombresOp, v_ApellidosOp
    FROM   "Operador" o
    INNER JOIN "Usuario" u ON u."Id" = o."IdUsuario"
    WHERE  o."Id" = _IdOperador;

    -- 5. Validar disponibilidad del operador
    IF NOT EXISTS (
        SELECT 1 FROM "Disponibilidad" d
        WHERE  d."IdOperador" = _IdOperador
          AND  d."NroDia"     = v_NroDia
          AND  d."Estado"     = 'ACTIVO'
          AND  d."HoraInicio" <= v_HoraInicio
          AND  d."HoraFin"    >= v_HoraFin
    ) THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El operador ' || v_NombresOp || ' ' || v_ApellidosOp ||
                    ' no tiene disponibilidad registrada para el horario ' ||
                    to_char(v_HoraInicio,'HH24:MI') || ' - ' ||
                    to_char(v_HoraFin,'HH24:MI') || '.';
        RETURN;
    END IF;

    -- 6. Leer placa grúa
    SELECT "Placa" INTO v_PlacaGrua FROM "Grua" WHERE "Id" = _IdGrua;

    -- 7. Validar conflicto de grúa
    IF EXISTS (
        SELECT 1 FROM "Reserva"
        WHERE  "IdGrua"          = _IdGrua
          AND  "FechaServicio"   = v_FechaServicio
          AND  "Id"             != _IdReserva
          AND  "Estado"          = 'ACTIVO'
          AND  "EstadoOperacion" != 'CANCELADO'
          AND  "HoraInicio"      < v_HoraFin
          AND  "HoraFin"         > v_HoraInicio
    ) THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'La grúa con placa ' || v_PlacaGrua ||
                    ' ya tiene asignado un servicio en el horario ' ||
                    to_char(v_HoraInicio,'HH24:MI') || ' - ' ||
                    to_char(v_HoraFin,'HH24:MI') || '.';
        RETURN;
    END IF;

    -- 8. Validar conflicto de operador
    IF EXISTS (
        SELECT 1 FROM "Reserva"
        WHERE  "IdOperador"      = _IdOperador
          AND  "FechaServicio"   = v_FechaServicio
          AND  "Id"             != _IdReserva
          AND  "Estado"          = 'ACTIVO'
          AND  "EstadoOperacion" != 'CANCELADO'
          AND  "HoraInicio"      < v_HoraFin
          AND  "HoraFin"         > v_HoraInicio
    ) THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El operador ' || v_NombresOp || ' ' || v_ApellidosOp ||
                    ' ya tiene asignado un servicio en el horario ' ||
                    to_char(v_HoraInicio,'HH24:MI') || ' - ' ||
                    to_char(v_HoraFin,'HH24:MI') || '.';
        RETURN;
    END IF;

    -- 9. Asignar
    UPDATE "Reserva"
    SET    "EstadoOperacion"    = 'ASIGNADO',
           "IdGrua"             = _IdGrua,
           "IdOperador"         = _IdOperador,
           "FechaActualizacion" = NOW(),
           "ActualizadoPor"     = _ActualizadoPor
    WHERE  "Id" = _IdReserva;

    COMMIT;
    _Exitoso := 1;
    _Mensaje := 'Servicio asignado correctamente a la grúa con placa ' ||
                v_PlacaGrua || ' y operador ' ||
                v_NombresOp || ' ' || v_ApellidosOp || '.';

END;
$$;


-- ── sp_ActualizarEnCursoReserva ─────────────────────────────
CREATE OR REPLACE PROCEDURE sp_ActualizarEnCursoReserva(
    _IdReserva      INT,
    _ActualizadoPor INT,
    INOUT _Exitoso  INT  DEFAULT 0,
    INOUT _Mensaje  TEXT DEFAULT ''
)
LANGUAGE plpgsql AS $$
DECLARE
    v_FechaServicio DATE;
BEGIN

    SELECT "FechaServicio" INTO v_FechaServicio
    FROM   "Reserva"
    WHERE  "Id"              = _IdReserva
      AND  "Estado"          = 'ACTIVO'
      AND  "EstadoOperacion" = 'ASIGNADO';

    IF v_FechaServicio IS NULL THEN
        _Exitoso := 0;
        _Mensaje := 'El servicio no existe o aún no se encuentra asignado';
        RETURN;
    END IF;

    /* IF CURRENT_DATE <> v_FechaServicio THEN
        _Exitoso := 0;
        _Mensaje := 'Este servicio está programado para el ' ||
                    to_char(v_FechaServicio, 'DD/MM/YYYY') ||
                    '. Solo puede iniciarse en esa fecha (hoy es ' ||
                    to_char(CURRENT_DATE, 'DD/MM/YYYY') || ')';
        RETURN;
    END IF; */

    UPDATE "Reserva"
    SET    "EstadoOperacion"    = 'ENCURSO',
           "HoraInicioReal"     = NOW(),
           "FechaActualizacion" = NOW(),
           "ActualizadoPor"     = _ActualizadoPor
    WHERE  "Id" = _IdReserva;

    COMMIT;
    _Exitoso := 1;
    _Mensaje := 'El servicio pasó a estar EN CURSO con éxito';

END;
$$;

-- ── sp_FinalizarServicio ─────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_FinalizarServicio(
    _IdReserva      INT,
    _ActualizadoPor INT,
    INOUT _Exitoso  INT  DEFAULT 0,
    INOUT _Mensaje  TEXT DEFAULT ''
)
LANGUAGE plpgsql AS $$
DECLARE
    v_FechaServicio DATE;
BEGIN

    SELECT "FechaServicio" INTO v_FechaServicio
    FROM   "Reserva"
    WHERE  "Id"              = _IdReserva
      AND  "Estado"          = 'ACTIVO'
      AND  "EstadoOperacion" = 'ENCURSO';

    IF v_FechaServicio IS NULL THEN
        _Exitoso := 0;
        _Mensaje := 'El servicio no existe o aún no se encuentra en curso';
        RETURN;
    END IF;

    /* IF CURRENT_DATE <> v_FechaServicio THEN
        _Exitoso := 0;
        _Mensaje := 'Este servicio está programado para el ' ||
                    to_char(v_FechaServicio, 'DD/MM/YYYY') ||
                    '. Solo puede finalizarse en esa fecha (hoy es ' ||
                    to_char(CURRENT_DATE, 'DD/MM/YYYY') || ')';
        RETURN;
    END IF; */

    UPDATE "Reserva"
    SET    "EstadoOperacion"    = 'FINALIZADO',
           "HoraFinReal"        = NOW(),
           "FechaActualizacion" = NOW(),
           "ActualizadoPor"     = _ActualizadoPor
    WHERE  "Id" = _IdReserva;

    COMMIT;
    _Exitoso := 1;
    _Mensaje := 'El servicio finalizó con éxito';

END;
$$;

-- ── sp_CancelarReserva ───────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_CancelarReserva(
    _Id                INT,
    _MotivoCancelacion VARCHAR(255),
    _ActualizadoPor    INT,
    INOUT _Exitoso     INT  DEFAULT 0,
    INOUT _Mensaje     TEXT DEFAULT ''
)
LANGUAGE plpgsql AS $$
DECLARE
    v_FechaServicio   DATE;
    v_HoraInicio      TIME;
    v_EstadoOperacion VARCHAR(20);
    v_SlotInicioDT    TIMESTAMP;
    v_TiempoCorte     INT;
BEGIN

    SELECT r."FechaServicio", r."HoraInicio", r."EstadoOperacion"
    INTO   v_FechaServicio, v_HoraInicio, v_EstadoOperacion
    FROM   "Reserva" r
    WHERE  r."Id"     = _Id
      AND  r."Estado" = 'ACTIVO'
    FOR UPDATE;

    IF v_FechaServicio IS NULL THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El servicio no existe o no se encuentra activo.';
        RETURN;
    END IF;

    IF v_EstadoOperacion IN ('CANCELADO', 'ENCURSO', 'FINALIZADO') THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El servicio no puede cancelarse porque se encuentra en estado '
                    || v_EstadoOperacion || '.';
        RETURN;
    END IF;

    v_SlotInicioDT := v_FechaServicio + v_HoraInicio;

    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" WHERE "Estado" = 'ACTIVO';

    IF v_FechaServicio = CURRENT_DATE
       AND v_SlotInicioDT - (v_TiempoCorte || ' hours')::INTERVAL <= NOW()
    THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'No es posible cancelar el servicio de las ' ||
                    to_char(v_HoraInicio,'HH24:MI:SS') ||
                    ', debe cancelarse con ' || v_TiempoCorte::TEXT ||
                    ' horas de anticipación.';
        RETURN;
    END IF;

    UPDATE "Reserva"
    SET    "EstadoOperacion"    = 'CANCELADO',
           "MotivoCancelacion"  = _MotivoCancelacion,
           "FechaActualizacion" = NOW(),
           "ActualizadoPor"     = _ActualizadoPor,
           "IdGrua"             = NULL,
           "IdOperador"         = NULL
    WHERE  "Id" = _Id;

    COMMIT;
    _Exitoso := 1;
    _Mensaje := 'Reserva cancelada correctamente.';

END;
$$;
-- ── sp_ReprogramarReserva ────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_ReprogramarReserva(
    _IdReserva       INT,
    _NuevaFecha      DATE,
    _NuevaHoraInicio TIME,
    _NuevoNroBloques INT,
    _ActualizadoPor  INT,
    _Rol             VARCHAR(20),
    INOUT _Exitoso        INT  DEFAULT 0,
    INOUT _Mensaje        TEXT DEFAULT '',
    INOUT _HorasConflicto TEXT DEFAULT NULL
)
LANGUAGE plpgsql AS $$
DECLARE
    v_NuevaHoraFin     TIME;
    v_SlotInicioDT     TIMESTAMP;
    v_SlotFinDT        TIMESTAMP;
    v_CantidadCarga    SMALLINT;
    v_EstadoOperacion  VARCHAR(20);
    v_TiempoCorte      INT;
    v_HorasExcepcion   TEXT;
    v_GruasDisponibles INT;
    v_MaxOcupacion     INT;
BEGIN

    LOCK TABLE "TimerReserva" IN SHARE ROW EXCLUSIVE MODE;
    LOCK TABLE "Reserva"      IN SHARE ROW EXCLUSIVE MODE;

    v_NuevaHoraFin := _NuevaHoraInicio + (_NuevoNroBloques || ' hours')::INTERVAL;
    v_SlotInicioDT := _NuevaFecha + _NuevaHoraInicio;
    v_SlotFinDT    := _NuevaFecha + v_NuevaHoraFin;
    IF v_NuevaHoraFin <= _NuevaHoraInicio THEN
        v_SlotFinDT := v_SlotFinDT + INTERVAL '1 day';
    END IF;

    SELECT r."CantidadCarga", r."EstadoOperacion"
    INTO   v_CantidadCarga, v_EstadoOperacion
    FROM   "Reserva" r
    WHERE  r."Id"     = _IdReserva
      AND  r."Estado" = 'ACTIVO';

    IF v_CantidadCarga IS NULL THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El servicio no existe o no se encuentra activo.';
        RETURN;
    END IF;

    IF v_EstadoOperacion IN ('CANCELADO', 'ENCURSO', 'FINALIZADO') THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El servicio no puede reprogramarse porque se encuentra en estado '
                    || v_EstadoOperacion || '.';
        RETURN;
    END IF;

    DELETE FROM "TimerReserva"
    WHERE "FechaCreacion" + ("TimerExpiracion" || ' minutes')::INTERVAL <= NOW();

    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" WHERE "Estado" = 'ACTIVO';

    IF _NuevaFecha = CURRENT_DATE
       AND v_SlotInicioDT - (v_TiempoCorte || ' hours')::INTERVAL <= NOW()
    THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'No es posible reprogramar a las ' ||
                    to_char(_NuevaHoraInicio,'HH24:MI:SS') ||
                    ' horas, debe reprogramar con ' || v_TiempoCorte::TEXT ||
                    ' horas de anticipación a la hora de inicio del servicio.';
        RETURN;
    END IF;

    IF _Rol <> 'ADMINISTRADOR' THEN
        SELECT string_agg(to_char(g.hora_dt::TIME,'HH24:MI'), ', ')
        INTO   v_HorasExcepcion
        FROM (
            SELECT v_SlotInicioDT + (s.n || ' hours')::INTERVAL AS hora_dt
            FROM   generate_series(0,
                       EXTRACT(EPOCH FROM (v_SlotFinDT - v_SlotInicioDT))::INT / 3600 - 1
                   ) AS s(n)
        ) g
        WHERE EXISTS (
            SELECT 1 FROM "Excepcion" e
            WHERE  e."Fecha"  = _NuevaFecha AND e."Estado" = 'ACTIVO'
              AND  g.hora_dt >= _NuevaFecha + e."TiempoInicio"
              AND  g.hora_dt <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                     THEN _NuevaFecha + e."TiempoFinal" + INTERVAL '1 day'
                                     ELSE _NuevaFecha + e."TiempoFinal" END
        );

        IF v_HorasExcepcion IS NOT NULL THEN
            ROLLBACK;
            _Exitoso        := 0;
            _Mensaje        := 'El horario seleccionado no está disponible por una excepción operativa.';
            _HorasConflicto := v_HorasExcepcion;
            RETURN;
        END IF;
    END IF;

    SELECT COUNT(*)::INT INTO v_GruasDisponibles
    FROM   "Grua"
    WHERE  "Grua"."Estado" = 'ACTIVO' AND "Grua"."EstadoOperacion" = 'OPERATIVA'
      AND  "Grua"."Capacidad" >= v_CantidadCarga;

    WITH
    "Horas" AS (
        SELECT v_SlotInicioDT + (s.n || ' hours')::INTERVAL AS "HoraDT"
        FROM   generate_series(0,
                   EXTRACT(EPOCH FROM (v_SlotFinDT - v_SlotInicioDT))::INT / 3600 - 1
               ) AS s(n)
    ),
    "SupplyPorNivel" AS (
        SELECT "Capacidad" AS "Lvl", COUNT(*)::INT AS "Supply"
        FROM   "Grua" WHERE "Grua"."Estado" = 'ACTIVO' AND "Grua"."EstadoOperacion" = 'OPERATIVA'
        GROUP BY "Capacidad"
    ),
    "HoraDemanda" AS (
        SELECT h."HoraDT", sp."Lvl", sp."Supply",
               COALESCE(r."Cnt",0) + COALESCE(t."Cnt",0) AS "Demand"
        FROM "Horas" h CROSS JOIN "SupplyPorNivel" sp
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "Reserva" rv
            WHERE  rv."FechaServicio"   = _NuevaFecha
              AND  rv."EstadoOperacion" <> 'CANCELADO'
              AND  rv."Id"             <> _IdReserva
              AND  rv."CantidadCarga"   = sp."Lvl"
              AND  h."HoraDT" >= rv."FechaServicio" + rv."HoraInicio"
              AND  h."HoraDT" <  CASE WHEN rv."HoraFin" <= rv."HoraInicio"
                                      THEN rv."FechaServicio" + rv."HoraFin" + INTERVAL '1 day'
                                      ELSE rv."FechaServicio" + rv."HoraFin" END
        ) r ON TRUE
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "TimerReserva" tr
            WHERE  tr."FechaServicio" = _NuevaFecha
              AND  tr."FechaCreacion" + (tr."TimerExpiracion" || ' minutes')::INTERVAL > NOW()
              AND  tr."CantidadCarga" = sp."Lvl"
              AND  h."HoraDT" >= tr."FechaServicio" + tr."HoraInicio"
              AND  h."HoraDT" <  CASE WHEN tr."HoraFin" <= tr."HoraInicio"
                                      THEN tr."FechaServicio" + tr."HoraFin" + INTERVAL '1 day'
                                      ELSE tr."FechaServicio" + tr."HoraFin" END
        ) t ON TRUE
    ),
    "Sufijos" AS (
        SELECT "HoraDT",
            SUM("Demand") OVER (PARTITION BY "HoraDT" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufD",
            SUM("Supply") OVER (PARTITION BY "HoraDT" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufG"
        FROM "HoraDemanda" WHERE "Lvl" < v_CantidadCarga
    ),
    "Overflow" AS (
        SELECT "HoraDT", GREATEST(0, MAX("SufD" - "SufG")) AS "Overflow"
        FROM   "Sufijos" GROUP BY "HoraDT"
    ),
    "DemandaDirecta" AS (
        SELECT "HoraDT", SUM("Demand") AS "DemandaK"
        FROM   "HoraDemanda" WHERE "Lvl" >= v_CantidadCarga GROUP BY "HoraDT"
    ),
    "OcupacionPorHora" AS (
        SELECT h."HoraDT",
               COALESCE(dd."DemandaK",0) + COALESCE(ov."Overflow",0) AS "OcupacionEfectiva"
        FROM "Horas" h
        LEFT JOIN "DemandaDirecta" dd ON dd."HoraDT" = h."HoraDT"
        LEFT JOIN "Overflow"       ov ON ov."HoraDT" = h."HoraDT"
    )
    SELECT COALESCE(MAX("OcupacionEfectiva"),0),
           string_agg(CASE WHEN "OcupacionEfectiva" >= v_GruasDisponibles
                           THEN to_char("HoraDT"::TIME,'HH24:MI') END, ', ')
    INTO   v_MaxOcupacion, _HorasConflicto
    FROM   "OcupacionPorHora";

    IF v_MaxOcupacion >= v_GruasDisponibles THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El nuevo horario no tiene disponibilidad para la carga solicitada.';
        RETURN;
    END IF;

    UPDATE "Reserva"
    SET    "FechaServicio"      = _NuevaFecha,
           "HoraInicio"         = _NuevaHoraInicio,
           "HoraFin"            = v_NuevaHoraFin,
           "NroBloques"         = _NuevoNroBloques,
           "IdGrua"             = NULL,
           "IdOperador"         = NULL,
           "EstadoOperacion"    = 'RESERVADO',
           "FechaActualizacion" = NOW(),
           "ActualizadoPor"     = _ActualizadoPor
    WHERE  "Id" = _IdReserva;

    COMMIT;
    _Exitoso        := 1;
    _Mensaje        := 'Servicio reprogramado correctamente.';
    _HorasConflicto := NULL;

END;
$$;
-- ── sp_ValidarHorario ────────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_ValidarHorario(
    _FechaServicio        DATE,
    _HoraInicio           TIME,
    _HoraFin              TIME,
    _CantidadCarga        SMALLINT,
    _IdCliente            INT,
    _IdOperador           INT,
    _CreadoPor            INT,
    _DireccionOrigen      TEXT,
    _CoordLatOrigen       VARCHAR(20),
    _CoordLonOrigen       VARCHAR(20),
    _DireccionDestino     TEXT,
    _CoordLatDestino      VARCHAR(20),
    _CoordLonDestino      VARCHAR(20),
    _DistanciaKm          DECIMAL(10,2),
    _TiempoEstimado       INT,
    _TiempoManiobra       INT,
    _TiempoRetorno        INT,
    _NroBloques           INT,
    _CostoKm              DECIMAL(10,2),
    _CostoBase            DECIMAL(10,2),
    _TimerExpiracion      SMALLINT,
    _EstadoOperacion      VARCHAR(50),
    _EstadoAdministrativo VARCHAR(50),
    _Estado               VARCHAR(10),
    _FechaCreacion        TIMESTAMP,
    _Rol                  VARCHAR(20),
    _TipoHorario          VARCHAR(50),
    INOUT _Exitoso        INT  DEFAULT 0,
    INOUT _Mensaje        TEXT DEFAULT '',
    INOUT _HorasConflicto TEXT DEFAULT NULL,
    INOUT _Id             INT  DEFAULT NULL
)
LANGUAGE plpgsql AS $$
DECLARE
    v_SlotInicioDT     TIMESTAMP;
    v_SlotFinDT        TIMESTAMP;
    v_TiempoCorte      INT;
    v_HorasExcepcion   TEXT;
    v_GruasDisponibles INT;
    v_MaxOcupacion     INT;
BEGIN

    LOCK TABLE "TimerReserva" IN SHARE ROW EXCLUSIVE MODE;
    LOCK TABLE "Reserva"      IN SHARE ROW EXCLUSIVE MODE;

    v_SlotInicioDT := _FechaServicio + _HoraInicio;
    v_SlotFinDT    := CASE WHEN _HoraFin <= _HoraInicio
                           THEN _FechaServicio + _HoraFin + INTERVAL '1 day'
                           ELSE _FechaServicio + _HoraFin END;

    DELETE FROM "TimerReserva"
    WHERE "FechaCreacion" + ("TimerExpiracion" || ' minutes')::INTERVAL <= NOW();

    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" po WHERE po."Estado" = 'ACTIVO';

    IF _FechaServicio = CURRENT_DATE
       AND v_SlotInicioDT - (v_TiempoCorte || ' hours')::INTERVAL <= NOW()
    THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'No es posible reservar a las ' ||
                    to_char(_HoraInicio,'HH24:MI:SS') ||
                    ' horas, debe reservar con ' || v_TiempoCorte::TEXT ||
                    ' horas de anticipación a la hora de inicio del servicio';
        RETURN;
    END IF;

    IF _Rol <> 'ADMINISTRADOR' THEN
        SELECT string_agg(to_char(g.hora_dt::TIME,'HH24:MI'), ', ')
        INTO   v_HorasExcepcion
        FROM (
            SELECT v_SlotInicioDT + (s.n || ' hours')::INTERVAL AS hora_dt
            FROM   generate_series(0,
                       EXTRACT(EPOCH FROM (v_SlotFinDT - v_SlotInicioDT))::INT / 3600 - 1
                   ) AS s(n)
        ) g
        WHERE EXISTS (
            SELECT 1 FROM "Excepcion" e
            WHERE  e."Fecha"  = _FechaServicio AND e."Estado" = 'ACTIVO'
              AND  g.hora_dt >= _FechaServicio + e."TiempoInicio"
              AND  g.hora_dt <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                     THEN _FechaServicio + e."TiempoFinal" + INTERVAL '1 day'
                                     ELSE _FechaServicio + e."TiempoFinal" END
        );

        IF v_HorasExcepcion IS NOT NULL THEN
            ROLLBACK;
            _Exitoso        := 0;
            _Mensaje        := 'El horario seleccionado no está disponible por una excepción operativa.';
            _HorasConflicto := v_HorasExcepcion;
            RETURN;
        END IF;
    END IF;

    SELECT COUNT(*)::INT INTO v_GruasDisponibles
    FROM   "Grua"
    WHERE  "Grua"."Estado" = 'ACTIVO' AND "Grua"."EstadoOperacion" = 'OPERATIVA'
      AND  "Grua"."Capacidad" >= _CantidadCarga;

    WITH
    "Horas" AS (
        SELECT v_SlotInicioDT + (s.n || ' hours')::INTERVAL AS "HoraDT"
        FROM   generate_series(0,
                   EXTRACT(EPOCH FROM (v_SlotFinDT - v_SlotInicioDT))::INT / 3600 - 1
               ) AS s(n)
    ),
    "SupplyPorNivel" AS (
        SELECT "Capacidad" AS "Lvl", COUNT(*)::INT AS "Supply"
        FROM   "Grua" WHERE "Grua"."Estado" = 'ACTIVO' AND "Grua"."EstadoOperacion" = 'OPERATIVA'
        GROUP BY "Capacidad"
    ),
    "HoraDemanda" AS (
        SELECT h."HoraDT", sp."Lvl", sp."Supply",
               COALESCE(r."Cnt",0) + COALESCE(t."Cnt",0) AS "Demand"
        FROM "Horas" h CROSS JOIN "SupplyPorNivel" sp
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "Reserva" rv
            WHERE  rv."FechaServicio"   = _FechaServicio
              AND  rv."EstadoOperacion" <> 'CANCELADO'
              AND  rv."CantidadCarga"   = sp."Lvl"
              AND  h."HoraDT" >= rv."FechaServicio" + rv."HoraInicio"
              AND  h."HoraDT" <  CASE WHEN rv."HoraFin" <= rv."HoraInicio"
                                      THEN rv."FechaServicio" + rv."HoraFin" + INTERVAL '1 day'
                                      ELSE rv."FechaServicio" + rv."HoraFin" END
        ) r ON TRUE
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "TimerReserva" tr
            WHERE  tr."FechaServicio" = _FechaServicio
              AND  tr."FechaCreacion" + (tr."TimerExpiracion" || ' minutes')::INTERVAL > NOW()
              AND  tr."CantidadCarga" = sp."Lvl"
              AND  h."HoraDT" >= tr."FechaServicio" + tr."HoraInicio"
              AND  h."HoraDT" <  CASE WHEN tr."HoraFin" <= tr."HoraInicio"
                                      THEN tr."FechaServicio" + tr."HoraFin" + INTERVAL '1 day'
                                      ELSE tr."FechaServicio" + tr."HoraFin" END
        ) t ON TRUE
    ),
    "Sufijos" AS (
        SELECT "HoraDT",
            SUM("Demand") OVER (PARTITION BY "HoraDT" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufD",
            SUM("Supply") OVER (PARTITION BY "HoraDT" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufG"
        FROM "HoraDemanda" WHERE "Lvl" < _CantidadCarga
    ),
    "Overflow" AS (
        SELECT "HoraDT", GREATEST(0, MAX("SufD" - "SufG")) AS "Overflow"
        FROM   "Sufijos" GROUP BY "HoraDT"
    ),
    "DemandaDirecta" AS (
        SELECT "HoraDT", SUM("Demand") AS "DemandaK"
        FROM   "HoraDemanda" WHERE "Lvl" >= _CantidadCarga GROUP BY "HoraDT"
    ),
    "OcupacionPorHora" AS (
        SELECT h."HoraDT",
               COALESCE(dd."DemandaK",0) + COALESCE(ov."Overflow",0) AS "OcupacionEfectiva"
        FROM "Horas" h
        LEFT JOIN "DemandaDirecta" dd ON dd."HoraDT" = h."HoraDT"
        LEFT JOIN "Overflow"       ov ON ov."HoraDT" = h."HoraDT"
    )
    SELECT COALESCE(MAX("OcupacionEfectiva"),0),
           string_agg(CASE WHEN "OcupacionEfectiva" >= v_GruasDisponibles
                           THEN to_char("HoraDT"::TIME,'HH24:MI') END, ', ')
    INTO   v_MaxOcupacion, _HorasConflicto
    FROM   "OcupacionPorHora";

    IF v_MaxOcupacion >= v_GruasDisponibles THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El horario seleccionado ya no tiene disponibilidad.';
        RETURN;
    END IF;

    INSERT INTO "TimerReserva" (
        "CantidadCarga","IdCliente","DireccionOrigen","CoordLatOrigen","CoordLonOrigen",
        "DireccionDestino","CoordLatDestino","CoordLonDestino","DistanciaKm",
        "TiempoEstimado","TiempoManiobra","TiempoRetorno","NroBloques",
        "CostoKm","CostoBase","EstadoOperacion","Estado","EstadoAdministrativo",
        "HoraInicio","HoraFin","FechaServicio","IdOperador",
        "FechaCreacion","FechaActualizacion","CreadoPor","ActualizadoPor",
        "TimerExpiracion","TipoHorario"
    ) VALUES (
        _CantidadCarga,_IdCliente,_DireccionOrigen,_CoordLatOrigen,_CoordLonOrigen,
        _DireccionDestino,_CoordLatDestino,_CoordLonDestino,_DistanciaKm,
        _TiempoEstimado,_TiempoManiobra,_TiempoRetorno,_NroBloques,
        _CostoKm,_CostoBase,_EstadoOperacion,_Estado,_EstadoAdministrativo,
        _HoraInicio,_HoraFin,_FechaServicio,_IdOperador,
        _FechaCreacion,NULL,_CreadoPor,NULL,
        _TimerExpiracion,_TipoHorario
    )
    RETURNING "Id" INTO _Id;

    COMMIT;
    _Exitoso := 1;
    _Mensaje := 'Horario bloqueado temporalmente.';

END;
$$;
-- ── sp_CreateReserva ─────────────────────────────────────────
CREATE OR REPLACE PROCEDURE sp_CreateReserva(
    _IdTimerReserva INT,
    _Vehiculos      tipo_vehiculo_detalle[],
    _Rol            VARCHAR(20),
    INOUT _Exitoso        INT  DEFAULT 0,
    INOUT _Mensaje        TEXT DEFAULT '',
    INOUT _HorasConflicto TEXT DEFAULT NULL,
    INOUT _Id             INT  DEFAULT NULL
)
LANGUAGE plpgsql AS $$
DECLARE
    v_FechaServicio  DATE;
    v_HoraInicio     TIME;
    v_HoraFin        TIME;
    v_SlotInicioDT   TIMESTAMP;
    v_SlotFinDT      TIMESTAMP;
    v_TiempoCorte    INT;
    v_HorasExcepcion TEXT;
    v_IdReserva      INT;
    v_CreadoPor      INT;
BEGIN

    LOCK TABLE "TimerReserva" IN SHARE ROW EXCLUSIVE MODE;
    LOCK TABLE "Reserva"      IN SHARE ROW EXCLUSIVE MODE;

    IF NOT EXISTS (
        SELECT 1 FROM "TimerReserva"
        WHERE  "Id" = _IdTimerReserva
          AND  "FechaCreacion" + ("TimerExpiracion" || ' minutes')::INTERVAL > NOW()
    ) THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'El tiempo de reserva ha expirado. Seleccione el horario nuevamente.';
        RETURN;
    END IF;

    SELECT tr."FechaServicio", tr."HoraInicio", tr."HoraFin"
    INTO   v_FechaServicio, v_HoraInicio, v_HoraFin
    FROM   "TimerReserva" tr WHERE tr."Id" = _IdTimerReserva;

    v_SlotInicioDT := v_FechaServicio + v_HoraInicio;
    v_SlotFinDT    := CASE WHEN v_HoraFin <= v_HoraInicio
                           THEN v_FechaServicio + v_HoraFin + INTERVAL '1 day'
                           ELSE v_FechaServicio + v_HoraFin END;

    IF _Rol <> 'ADMINISTRADOR' THEN
        SELECT string_agg(to_char(g.hora_dt::TIME,'HH24:MI'), ', ')
        INTO   v_HorasExcepcion
        FROM (
            SELECT v_SlotInicioDT + (s.n || ' hours')::INTERVAL AS hora_dt
            FROM   generate_series(0,
                       EXTRACT(EPOCH FROM (v_SlotFinDT - v_SlotInicioDT))::INT / 3600 - 1
                   ) AS s(n)
        ) g
        WHERE EXISTS (
            SELECT 1 FROM "Excepcion" e
            WHERE  e."Fecha"  = v_FechaServicio AND e."Estado" = 'ACTIVO'
              AND  g.hora_dt >= v_FechaServicio + e."TiempoInicio"
              AND  g.hora_dt <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                     THEN v_FechaServicio + e."TiempoFinal" + INTERVAL '1 day'
                                     ELSE v_FechaServicio + e."TiempoFinal" END
        );

        IF v_HorasExcepcion IS NOT NULL THEN
            ROLLBACK;
            _Exitoso        := 0;
            _Mensaje        := 'El horario seleccionado no está disponible por una excepción operativa.';
            _HorasConflicto := v_HorasExcepcion;
            RETURN;
        END IF;
    END IF;

    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" po WHERE po."Estado" = 'ACTIVO';

    IF v_FechaServicio = CURRENT_DATE
       AND v_SlotInicioDT - (v_TiempoCorte || ' hours')::INTERVAL <= NOW()
    THEN
        ROLLBACK;
        _Exitoso := 0;
        _Mensaje := 'No es posible guardar la reserva a las ' ||
                    to_char(v_HoraInicio,'HH24:MI:SS') ||
                    ' horas, debe reservar con ' || v_TiempoCorte::TEXT ||
                    ' horas de anticipación a la hora de inicio del servicio';
        RETURN;
    END IF;

    INSERT INTO "Reserva" (
        "CantidadCarga","IdCliente","DireccionOrigen","CoordLatOrigen","CoordLonOrigen",
        "DireccionDestino","CoordLatDestino","CoordLonDestino","DistanciaKm",
        "TiempoEstimado","TiempoManiobra","TiempoRetorno","NroBloques",
        "CostoKm","CostoBase","EstadoOperacion","Estado","EstadoAdministrativo",
        "HoraInicio","HoraFin","FechaServicio","IdOperador",
        "FechaCreacion","FechaActualizacion","CreadoPor","ActualizadoPor","TipoHorario"
    )
    SELECT
        tr."CantidadCarga",tr."IdCliente",tr."DireccionOrigen",tr."CoordLatOrigen",tr."CoordLonOrigen",
        tr."DireccionDestino",tr."CoordLatDestino",tr."CoordLonDestino",tr."DistanciaKm",
        tr."TiempoEstimado",tr."TiempoManiobra",tr."TiempoRetorno",tr."NroBloques",
        tr."CostoKm",tr."CostoBase",tr."EstadoOperacion",tr."Estado",tr."EstadoAdministrativo",
        tr."HoraInicio",tr."HoraFin",tr."FechaServicio",tr."IdOperador",
        NOW(),NULL,tr."CreadoPor",NULL,tr."TipoHorario"
    FROM "TimerReserva" tr WHERE tr."Id" = _IdTimerReserva
    RETURNING "Id" INTO v_IdReserva;

    SELECT tr."CreadoPor" INTO v_CreadoPor
    FROM   "TimerReserva" tr WHERE tr."Id" = _IdTimerReserva;

    INSERT INTO "Vehiculo" (
        "Tipo","Placa","Modelo","Observacion",
        "IdReserva","FechaCreacion","FechaActualizacion",
        "CreadoPor","ActualizadoPor","Estado"
    )
    SELECT v."Tipo",v."Placa",v."Descripcion",v."Observacion",
           v_IdReserva,NOW(),NULL,v_CreadoPor,NULL,'ACTIVO'
    FROM   UNNEST(_Vehiculos) AS v;

    DELETE FROM "TimerReserva" WHERE "Id" = _IdTimerReserva;

    COMMIT;
    _Exitoso := 1;
    _Mensaje := 'Reserva creada exitosamente.';
    _Id      := v_IdReserva;

END;
$$;

-- ============================================================
-- SECCIÓN 7: FUNCTIONS  (solo retornan filas, sin transacción)
-- ============================================================
-- Llamada desde app: SELECT * FROM sp_xxx(p1, p2, ...)
-- ────────────────────────────────────────────────────────────

-- ── fn_ListClientes ──────────────────────────────────────────
CREATE OR REPLACE FUNCTION fn_ListClientes(
    _Estado VARCHAR(20),
    _Id     INT
)
RETURNS TABLE(
    "Id"             INT,
    "Empresa"        VARCHAR(100),
    "NomContacto"    VARCHAR(100),
    "NroContacto"    VARCHAR(20),
    "CorreoContacto" VARCHAR(100),
    "TarifaBase"     DECIMAL(10,2),
    "TarifaKm"       DECIMAL(10,2),
    "Estado"         VARCHAR(20),
    "Alias"          VARCHAR(10),
    "Contraseña"     VARCHAR(100)
)
LANGUAGE plpgsql AS $$
BEGIN
    RETURN QUERY
    SELECT nte."Id",nte."Empresa",nte."NomContacto",nte."NroContacto",
           nte."CorreoContacto",nte."TarifaBase",nte."TarifaKm",nte."Estado",
           rio."Alias",rio."Contraseña"
    FROM   "Cliente" nte
    INNER JOIN "Usuario" rio ON nte."IdUsuario" = rio."Id"
    WHERE  (_Estado IS NULL OR nte."Estado" = _Estado)
      AND  (_Id     IS NULL OR nte."Id"     = _Id);
END;
$$;

-- ── fn_ListReservas ──────────────────────────────────────────
DROP FUNCTION IF EXISTS fn_ListReservas(VARCHAR, INT, DATE, INT);
CREATE OR REPLACE FUNCTION fn_ListReservas(
    _EstadoOperacion VARCHAR(20),
    _Id              INT,
    _FechaServicio   DATE,
    _IdOperador      INT
)
RETURNS TABLE(
    "Id"               INT,
    "DireccionOrigen"  TEXT,
    "CoordLatOrigen"   VARCHAR(20),
    "CoordLonOrigen"   VARCHAR(20),
    "DireccionDestino" TEXT,
    "CoordLatDestino"  VARCHAR(20),
    "CoordLonDestino"  VARCHAR(20),
    "CantidadCarga"    SMALLINT,
    "FechaServicio"    DATE,
    "HoraInicio"       TIME,
    "HoraFin"          TIME,
    "NroBloques"       INT,
    "DistanciaKm"      DECIMAL(10,2),
    "TiempoEstimado"   INT,
    "TiempoManiobra"   INT,
    "TiempoRetorno"    INT,
    "Estado"           VARCHAR(10),
    "EstadoOperacion"  VARCHAR(50),
    "NombreCliente"    TEXT,
    "GruaAsignada"     TEXT,
    "OperadorAsignado" TEXT,
    "Vehiculos"        JSON
)
LANGUAGE plpgsql AS $$
BEGIN
    RETURN QUERY
    SELECT r."Id",
           r."DireccionOrigen",
           r."CoordLatOrigen",
           r."CoordLonOrigen",
           r."DireccionDestino",
           r."CoordLatDestino",
           r."CoordLonDestino",
           r."CantidadCarga",
           r."FechaServicio",r."HoraInicio",r."HoraFin",r."NroBloques",
           r."DistanciaKm",r."TiempoEstimado",r."TiempoManiobra",r."TiempoRetorno",
           r."Estado",r."EstadoOperacion",
           (u_c."Nombres" || ' ' || u_c."Apellidos")::TEXT,
           CASE WHEN g."Id" IS NOT NULL
                THEN g."Placa" || ' - ' || g."Marca" || ' ' || g."Modelo"
                ELSE NULL END::TEXT,
           CASE WHEN o."Id" IS NOT NULL
                THEN u."Nombres" || ' ' || u."Apellidos"
                ELSE NULL END::TEXT,
           COALESCE(
               (SELECT json_agg(
                   json_build_object(
                       'Placa',       v."Placa",
                       'Modelo',      v."Modelo",
                       'Tipo',        v."Tipo",
                       'Observacion', v."Observacion"
                   ) ORDER BY v."Id"
               )
               FROM "Vehiculo" v
               WHERE v."IdReserva" = r."Id" AND v."Estado" = 'ACTIVO'),
               '[]'::json
           )
    FROM   "Reserva" r
    LEFT JOIN "Grua"     g   ON g."Id"        = r."IdGrua"
    LEFT JOIN "Operador" o   ON o."Id"        = r."IdOperador"
    LEFT JOIN "Usuario"  u   ON o."IdUsuario" = u."Id"
    LEFT JOIN "Cliente"  c   ON c."Id"        = r."IdCliente"
    LEFT JOIN "Usuario"  u_c ON u_c."Id"      = c."IdUsuario"
    WHERE  (_EstadoOperacion IS NULL OR r."EstadoOperacion" = _EstadoOperacion)
      AND  (_Id              IS NULL OR r."Id"              = _Id)
      AND  (_FechaServicio   IS NULL OR r."FechaServicio"   = _FechaServicio)
      AND  (_IdOperador      IS NULL OR r."IdOperador"      = _IdOperador)
      AND  r."Estado" = 'ACTIVO'
    ORDER BY r."FechaServicio", r."HoraInicio", r."HoraFin", r."Id";
END;
$$;

-- ── fn_LoginUsuario ──────────────────────────────────────────
DROP FUNCTION IF EXISTS fn_LoginUsuario(VARCHAR, VARCHAR);
CREATE OR REPLACE FUNCTION fn_LoginUsuario(
    _Identificador VARCHAR(100),
    _Contrasena    VARCHAR(100)
)
RETURNS TABLE(
    "Exitoso"              INT,
    "Mensaje"              TEXT,
    "Id"                   INT,
    "Alias"                VARCHAR(10),
    "Nombres"              VARCHAR(100),
    "Apellidos"            VARCHAR(100),
    "Correo"               VARCHAR(100),
    "Telefono"             VARCHAR(50),
    "Rol"                  VARCHAR(100),
    "IdCliente"            INT,
    "TarifaKmCliente"      DECIMAL(10,2),
    "TarifaBaseCliente"    DECIMAL(10,2),
    "EmpresaCliente"       VARCHAR(100),
    "IdOperador"           INT,
    "NroLicencia"          VARCHAR(9),
    "FecVenLic"            DATE,
    "ServiciosCompletados" INT
)
LANGUAGE plpgsql AS $$
DECLARE
    v_UsuarioId INT;
    v_Alias     VARCHAR(10);
    v_Nombres   VARCHAR(100);
    v_Apellidos VARCHAR(100);
    v_Correo    VARCHAR(100);
    v_Telefono  VARCHAR(50);
    v_Rol       VARCHAR(100);
    v_Estado    VARCHAR(20);
BEGIN
    SELECT u."Id",u."Alias",u."Nombres",u."Apellidos",
           u."Correo",u."Telefono",u."Rol",u."Estado"
    INTO   v_UsuarioId,v_Alias,v_Nombres,v_Apellidos,
           v_Correo,v_Telefono,v_Rol,v_Estado
    FROM   "Usuario" u
    WHERE  (
        (u."Rol" IN ('CLIENTE','OPERADOR','STAFF') AND u."Alias" = _Identificador)
        OR (u."Rol" = 'ADMINISTRADOR' AND u."Correo" = _Identificador)
    )
    AND u."Contraseña" = _Contrasena;

    IF v_UsuarioId IS NULL THEN
        RETURN QUERY SELECT 0,'Credenciales incorrectas'::TEXT,
            NULL::INT,NULL::VARCHAR(10),NULL::VARCHAR(100),NULL::VARCHAR(100),
            NULL::VARCHAR(100),NULL::VARCHAR(50),NULL::VARCHAR(100),
            NULL::INT,NULL::DECIMAL(10,2),NULL::DECIMAL(10,2),NULL::VARCHAR(100),
            NULL::INT,NULL::VARCHAR(9),NULL::DATE,NULL::INT;
        RETURN;
    END IF;

    IF v_Estado <> 'ACTIVO' THEN
        RETURN QUERY SELECT 0,'Usuario inactivo'::TEXT,
            NULL::INT,NULL::VARCHAR(10),NULL::VARCHAR(100),NULL::VARCHAR(100),
            NULL::VARCHAR(100),NULL::VARCHAR(50),NULL::VARCHAR(100),
            NULL::INT,NULL::DECIMAL(10,2),NULL::DECIMAL(10,2),NULL::VARCHAR(100),
            NULL::INT,NULL::VARCHAR(9),NULL::DATE,NULL::INT;
        RETURN;
    END IF;

    RETURN QUERY
    SELECT 1,'OK'::TEXT,
           v_UsuarioId,v_Alias,v_Nombres,v_Apellidos,
           v_Correo,v_Telefono,v_Rol,
           c."Id",c."TarifaKm",c."TarifaBase",c."Empresa",
           op."Id",
           op."NroLicencia",
           op."FecVenLic",
           (SELECT COUNT(*)::INT FROM "Reserva" r
            WHERE r."IdOperador" = op."Id"
              AND r."EstadoOperacion" = 'FINALIZADO')
    FROM   (SELECT 1) base
    LEFT JOIN "Cliente"  c  ON c."IdUsuario"  = v_UsuarioId AND v_Rol = 'CLIENTE'
    LEFT JOIN "Operador" op ON op."IdUsuario" = v_UsuarioId AND v_Rol = 'OPERADOR';
END;
$$;

-- ── fn_ParametroOperativo ────────────────────────────────────
CREATE OR REPLACE FUNCTION fn_ParametroOperativo()
RETURNS TABLE(
    "TiempoMargenManiobra" SMALLINT,
    "TiempoRetornoBase"    SMALLINT,
    "UmbralLargaDistancia" DECIMAL(10,2),
    "TiempoTolerancia"     SMALLINT,
    "FechaCreacion"        TIMESTAMP(6),
    "FechaActualizacion"   TIMESTAMP(6),
    "CreadoPor"            INT,
    "ActualizadoPor"       INT,
    "Estado"               VARCHAR(10),
    "TiempoCorte"          SMALLINT,
    "TimerAdministrativo"  SMALLINT,
    "TimerCliente"         SMALLINT,
    "ZonaHoraria"          VARCHAR(50),
    "MinutosCerca"         SMALLINT,
    "MinutosMedio"         SMALLINT,
    "CoordLatMaps"         VARCHAR(20),
    "CoordLonMaps"         VARCHAR(20),
    "MetrosCercania"       DECIMAL(10,2)
)
LANGUAGE plpgsql AS $$
BEGIN
    RETURN QUERY
    SELECT p."TiempoMargenManiobra",p."TiempoRetornoBase",p."UmbralLargaDistancia",
           p."TiempoTolerancia",p."FechaCreacion",p."FechaActualizacion",
           p."CreadoPor",p."ActualizadoPor",p."Estado",p."TiempoCorte",
           p."TimerAdministrativo",p."TimerCliente",p."ZonaHoraria",
           p."MinutosCerca",p."MinutosMedio",
           p."CoordLatMaps",p."CoordLonMaps",p."MetrosCercania"
    FROM   "ParametroOperativo" p LIMIT 1;
END;
$$;

-- ── fn_TarifarioGlobal ───────────────────────────────────────
CREATE OR REPLACE FUNCTION fn_TarifarioGlobal()
RETURNS TABLE("TarifaBase" DECIMAL(10,2), "TarifaKm" DECIMAL(10,2), "Estado" VARCHAR(10))
LANGUAGE plpgsql AS $$
BEGIN
    RETURN QUERY
    SELECT tg."TarifaBase",tg."TarifaKm",tg."Estado"
    FROM   "TarifarioGlobal" tg LIMIT 1;
END;
$$;

-- ── fn_ListHorariosDisponibles ───────────────────────────────
-- [CAMBIO] CTE recursiva → generate_series
-- [CAMBIO] OUTER APPLY   → LEFT JOIN LATERAL ... ON TRUE
-- [CAMBIO] DATEPART(WEEKDAY,d) → EXTRACT(DOW FROM d)::INT + 1
-- [CAMBIO] OPTION(MAXRECURSION 100) → eliminado
CREATE OR REPLACE FUNCTION fn_ListHorariosDisponibles(
    _FechaSeleccionada DATE,
    _Rol               VARCHAR(20),
    _Capacidad         SMALLINT
)
RETURNS TABLE("Hora" TIME, "Estado" VARCHAR(10))
LANGUAGE plpgsql AS $$
DECLARE
    v_NroDia         SMALLINT;
    v_HoraInicio     TIME;
    v_HoraFinal      TIME;
    v_MaxOffset      INT;
    v_FechaInicioDT  TIMESTAMP;
    v_TiempoCorte    INT;
    v_GruasCapacidad INT;
BEGIN

    v_NroDia := (EXTRACT(DOW FROM _FechaSeleccionada)::INT + 1)::SMALLINT;

    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" po WHERE po."Estado" = 'ACTIVO';

    SELECT ch."HoraInicio",ch."HoraFinal"
    INTO   v_HoraInicio,v_HoraFinal
    FROM   "ConfiguracionHorario" ch
    WHERE  ch."NroDia" = v_NroDia AND ch."Estado" = 'ACTIVO' AND ch."Rol" = _Rol;

    IF v_HoraInicio IS NULL THEN RETURN; END IF;

    v_FechaInicioDT := _FechaSeleccionada + v_HoraInicio;
    v_MaxOffset     := CASE WHEN v_HoraFinal <= v_HoraInicio
                            THEN EXTRACT(EPOCH FROM (v_HoraFinal - v_HoraInicio))::INT / 3600 + 24
                            ELSE EXTRACT(EPOCH FROM (v_HoraFinal - v_HoraInicio))::INT / 3600
                       END;

    SELECT COUNT(*)::INT INTO v_GruasCapacidad
    FROM   "Grua"
    WHERE  "Grua"."Estado" = 'ACTIVO' AND "Grua"."EstadoOperacion" = 'OPERATIVA' AND "Grua"."Capacidad" >= _Capacidad;

    RETURN QUERY
    WITH
    "HorasGeneradas" AS (
        SELECT s.n AS "OffsetHoras" FROM generate_series(0, v_MaxOffset) AS s(n)
    ),
    "SupplyPorNivel" AS (
        SELECT g."Capacidad" AS "Lvl", COUNT(*)::INT AS "Supply"
        FROM   "Grua" g WHERE g."Estado" = 'ACTIVO' AND g."EstadoOperacion" = 'OPERATIVA'
        GROUP BY g."Capacidad"
    ),
    "SlotDemanda" AS (
        SELECT h."OffsetHoras",
               v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL AS "SlotDT",
               s."Lvl", s."Supply",
               COALESCE(r."Cnt",0) + COALESCE(t."Cnt",0) AS "Demand"
        FROM "HorasGeneradas" h CROSS JOIN "SupplyPorNivel" s
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "Reserva" r2
            WHERE  r2."FechaServicio"   = _FechaSeleccionada
              AND  r2."EstadoOperacion" <> 'CANCELADO'
              AND  r2."CantidadCarga"   = s."Lvl"
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       >= r2."FechaServicio" + r2."HoraInicio"
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       <  CASE WHEN r2."HoraFin" <= r2."HoraInicio"
                                THEN r2."FechaServicio" + r2."HoraFin" + INTERVAL '1 day'
                                ELSE r2."FechaServicio" + r2."HoraFin" END
        ) r ON TRUE
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "TimerReserva" tr2
            WHERE  tr2."FechaServicio" = _FechaSeleccionada
              AND  tr2."CantidadCarga" = s."Lvl"
              AND  tr2."FechaCreacion" + (tr2."TimerExpiracion" || ' minutes')::INTERVAL > NOW()
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       >= tr2."FechaServicio" + tr2."HoraInicio"
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       <  CASE WHEN tr2."HoraFin" <= tr2."HoraInicio"
                                THEN tr2."FechaServicio" + tr2."HoraFin" + INTERVAL '1 day'
                                ELSE tr2."FechaServicio" + tr2."HoraFin" END
        ) t ON TRUE
    ),
    "Sufijos" AS (
        SELECT "OffsetHoras",
            SUM("Demand") OVER (PARTITION BY "OffsetHoras" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufD",
            SUM("Supply") OVER (PARTITION BY "OffsetHoras" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufG"
        FROM "SlotDemanda" WHERE "Lvl" < _Capacidad
    ),
    "Overflow" AS (
        SELECT "OffsetHoras", GREATEST(0,MAX("SufD"-"SufG")) AS "Overflow"
        FROM   "Sufijos" GROUP BY "OffsetHoras"
    ),
    "DemandaDirecta" AS (
        SELECT "OffsetHoras", SUM("Demand") AS "DemandaK"
        FROM   "SlotDemanda" WHERE "Lvl" >= _Capacidad GROUP BY "OffsetHoras"
    ),
    "SlotConsolidado" AS (
        SELECT h."OffsetHoras",
               v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL AS "SlotDT",
               COALESCE(dd."DemandaK",0) + COALESCE(ov."Overflow",0) AS "OcupacionEfectiva"
        FROM "HorasGeneradas" h
        LEFT JOIN "DemandaDirecta" dd ON dd."OffsetHoras" = h."OffsetHoras"
        LEFT JOIN "Overflow"       ov ON ov."OffsetHoras" = h."OffsetHoras"
    )
    SELECT sc."SlotDT"::TIME,
           CASE WHEN EXISTS (
               SELECT 1 FROM "Excepcion" e
               WHERE  e."Fecha" = _FechaSeleccionada AND e."Estado" = 'ACTIVO'
                 AND  sc."SlotDT" >= _FechaSeleccionada + e."TiempoInicio"
                 AND  sc."SlotDT" <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                          THEN _FechaSeleccionada + e."TiempoFinal" + INTERVAL '1 day'
                                          ELSE _FechaSeleccionada + e."TiempoFinal" END
           ) THEN 'EXCEPCION' ELSE 'DISPONIBLE' END::VARCHAR(10)
    FROM "SlotConsolidado" sc
    WHERE
        (_Rol = 'ADMINISTRADOR' OR NOT EXISTS (
            SELECT 1 FROM "Excepcion" e
            WHERE  e."Fecha" = _FechaSeleccionada AND e."Estado" = 'ACTIVO'
              AND  sc."SlotDT" >= _FechaSeleccionada + e."TiempoInicio"
              AND  sc."SlotDT" <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                       THEN _FechaSeleccionada + e."TiempoFinal" + INTERVAL '1 day'
                                       ELSE _FechaSeleccionada + e."TiempoFinal" END
        ))
        AND (_FechaSeleccionada > CURRENT_DATE
             OR sc."SlotDT" - (v_TiempoCorte || ' hours')::INTERVAL > NOW())
        AND sc."OcupacionEfectiva" < v_GruasCapacidad
    ORDER BY sc."SlotDT";
END;
$$;

-- ── fn_ListHorariosReprogramacion ────────────────────────────
CREATE OR REPLACE FUNCTION fn_ListHorariosReprogramacion(
    _FechaSeleccionada DATE,
    _Rol               VARCHAR(20),
    _Capacidad         SMALLINT,
    _IdReserva         INT
)
RETURNS TABLE("Hora" TIME, "Estado" VARCHAR(10))
LANGUAGE plpgsql AS $$
DECLARE
    v_NroDia         SMALLINT;
    v_HoraInicio     TIME;
    v_HoraFinal      TIME;
    v_MaxOffset      INT;
    v_FechaInicioDT  TIMESTAMP;
    v_TiempoCorte    INT;
    v_GruasCapacidad INT;
BEGIN

    v_NroDia := (EXTRACT(DOW FROM _FechaSeleccionada)::INT + 1)::SMALLINT;

    SELECT "TiempoCorte" INTO v_TiempoCorte
    FROM   "ParametroOperativo" po WHERE po."Estado" = 'ACTIVO';

    SELECT ch."HoraInicio",ch."HoraFinal"
    INTO   v_HoraInicio,v_HoraFinal
    FROM   "ConfiguracionHorario" ch
    WHERE  ch."NroDia" = v_NroDia AND ch."Estado" = 'ACTIVO' AND ch."Rol" = _Rol;

    IF v_HoraInicio IS NULL THEN RETURN; END IF;

    v_FechaInicioDT := _FechaSeleccionada + v_HoraInicio;
    v_MaxOffset     := CASE WHEN v_HoraFinal <= v_HoraInicio
                            THEN EXTRACT(EPOCH FROM (v_HoraFinal - v_HoraInicio))::INT / 3600 + 24
                            ELSE EXTRACT(EPOCH FROM (v_HoraFinal - v_HoraInicio))::INT / 3600
                       END;

    SELECT COUNT(*)::INT INTO v_GruasCapacidad
    FROM   "Grua"
    WHERE  "Grua"."Estado" = 'ACTIVO' AND "Grua"."EstadoOperacion" = 'OPERATIVA' AND "Grua"."Capacidad" >= _Capacidad;

    RETURN QUERY
    WITH
    "HorasGeneradas" AS (
        SELECT s.n AS "OffsetHoras" FROM generate_series(0, v_MaxOffset) AS s(n)
    ),
    "SupplyPorNivel" AS (
        SELECT g."Capacidad" AS "Lvl", COUNT(*)::INT AS "Supply"
        FROM   "Grua" g WHERE g."Estado" = 'ACTIVO' AND g."EstadoOperacion" = 'OPERATIVA'
        GROUP BY g."Capacidad"
    ),
    "SlotDemanda" AS (
        SELECT h."OffsetHoras",
               v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL AS "SlotDT",
               s."Lvl", s."Supply",
               COALESCE(r."Cnt",0) + COALESCE(t."Cnt",0) AS "Demand"
        FROM "HorasGeneradas" h CROSS JOIN "SupplyPorNivel" s
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "Reserva" r2
            WHERE  r2."FechaServicio"   = _FechaSeleccionada
              AND  r2."EstadoOperacion" <> 'CANCELADO'
              AND  r2."Id"             <> _IdReserva
              AND  r2."CantidadCarga"   = s."Lvl"
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       >= r2."FechaServicio" + r2."HoraInicio"
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       <  CASE WHEN r2."HoraFin" <= r2."HoraInicio"
                                THEN r2."FechaServicio" + r2."HoraFin" + INTERVAL '1 day'
                                ELSE r2."FechaServicio" + r2."HoraFin" END
        ) r ON TRUE
        LEFT JOIN LATERAL (
            SELECT COUNT(*)::INT AS "Cnt" FROM "TimerReserva" tr2
            WHERE  tr2."FechaServicio" = _FechaSeleccionada
              AND  tr2."CantidadCarga" = s."Lvl"
              AND  tr2."FechaCreacion" + (tr2."TimerExpiracion" || ' minutes')::INTERVAL > NOW()
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       >= tr2."FechaServicio" + tr2."HoraInicio"
              AND  (v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL)
                       <  CASE WHEN tr2."HoraFin" <= tr2."HoraInicio"
                                THEN tr2."FechaServicio" + tr2."HoraFin" + INTERVAL '1 day'
                                ELSE tr2."FechaServicio" + tr2."HoraFin" END
        ) t ON TRUE
    ),
    "Sufijos" AS (
        SELECT "OffsetHoras",
            SUM("Demand") OVER (PARTITION BY "OffsetHoras" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufD",
            SUM("Supply") OVER (PARTITION BY "OffsetHoras" ORDER BY "Lvl" DESC ROWS UNBOUNDED PRECEDING) AS "SufG"
        FROM "SlotDemanda" WHERE "Lvl" < _Capacidad
    ),
    "Overflow" AS (
        SELECT "OffsetHoras", GREATEST(0,MAX("SufD"-"SufG")) AS "Overflow"
        FROM   "Sufijos" GROUP BY "OffsetHoras"
    ),
    "DemandaDirecta" AS (
        SELECT "OffsetHoras", SUM("Demand") AS "DemandaK"
        FROM   "SlotDemanda" WHERE "Lvl" >= _Capacidad GROUP BY "OffsetHoras"
    ),
    "SlotConsolidado" AS (
        SELECT h."OffsetHoras",
               v_FechaInicioDT + (h."OffsetHoras" || ' hours')::INTERVAL AS "SlotDT",
               COALESCE(dd."DemandaK",0) + COALESCE(ov."Overflow",0) AS "OcupacionEfectiva"
        FROM "HorasGeneradas" h
        LEFT JOIN "DemandaDirecta" dd ON dd."OffsetHoras" = h."OffsetHoras"
        LEFT JOIN "Overflow"       ov ON ov."OffsetHoras" = h."OffsetHoras"
    )
    SELECT sc."SlotDT"::TIME,
           CASE WHEN EXISTS (
               SELECT 1 FROM "Excepcion" e
               WHERE  e."Fecha" = _FechaSeleccionada AND e."Estado" = 'ACTIVO'
                 AND  sc."SlotDT" >= _FechaSeleccionada + e."TiempoInicio"
                 AND  sc."SlotDT" <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                          THEN _FechaSeleccionada + e."TiempoFinal" + INTERVAL '1 day'
                                          ELSE _FechaSeleccionada + e."TiempoFinal" END
           ) THEN 'EXCEPCION' ELSE 'DISPONIBLE' END::VARCHAR(10)
    FROM "SlotConsolidado" sc
    WHERE
        (_Rol = 'ADMINISTRADOR' OR NOT EXISTS (
            SELECT 1 FROM "Excepcion" e
            WHERE  e."Fecha" = _FechaSeleccionada AND e."Estado" = 'ACTIVO'
              AND  sc."SlotDT" >= _FechaSeleccionada + e."TiempoInicio"
              AND  sc."SlotDT" <  CASE WHEN e."TiempoFinal" <= e."TiempoInicio"
                                       THEN _FechaSeleccionada + e."TiempoFinal" + INTERVAL '1 day'
                                       ELSE _FechaSeleccionada + e."TiempoFinal" END
        ))
        AND (_FechaSeleccionada > CURRENT_DATE
             OR sc."SlotDT" - (v_TiempoCorte || ' hours')::INTERVAL > NOW())
        AND sc."OcupacionEfectiva" < v_GruasCapacidad
    ORDER BY sc."SlotDT";
END;
$$;

-- ── sp_SugerirAsignacion (dividida en 2) ─────────────────────
-- [CAMBIO] SQL Server retornaba 2 result sets en un EXEC.
-- PostgreSQL no soporta múltiples result sets por función.
-- Se divide en fn_SugerirAsignacion_Gruas y fn_SugerirAsignacion_Operadores.
CREATE OR REPLACE FUNCTION fn_SugerirAsignacion_Gruas(_IdReserva INT)
RETURNS TABLE(
    "Id"          INT,
    "Placa"       VARCHAR(10),
    "Marca"       VARCHAR(30),
    "Modelo"      VARCHAR(30),
    "Capacidad"   SMALLINT,
    "UltLatitud"  VARCHAR(20),
    "UltLongitud" VARCHAR(20)
)
LANGUAGE plpgsql AS $$
DECLARE
    v_CantidadCarga SMALLINT;
    v_FechaServicio DATE;
    v_HoraInicio    TIME;
    v_HoraFin       TIME;
BEGIN
    SELECT r."CantidadCarga",r."FechaServicio",r."HoraInicio",r."HoraFin"
    INTO   v_CantidadCarga,v_FechaServicio,v_HoraInicio,v_HoraFin
    FROM   "Reserva" r WHERE r."Id" = _IdReserva;

    RETURN QUERY
    SELECT g."Id",g."Placa",g."Marca",g."Modelo",g."Capacidad",
           ult."CoordLatDestino",ult."CoordLonDestino"
    FROM "Grua" g
    LEFT JOIN (
        SELECT r2."CoordLatDestino",r2."CoordLonDestino",r2."IdGrua",
               ROW_NUMBER() OVER (PARTITION BY r2."IdGrua" ORDER BY r2."HoraFin" DESC) AS rn
        FROM   "Reserva" r2
        WHERE  r2."EstadoOperacion" != 'CANCELADO'
          AND  r2."FechaServicio"    = v_FechaServicio
          AND  r2."HoraFin"         <= v_HoraInicio
          AND  r2."Estado"           = 'ACTIVO'
    ) ult ON ult."IdGrua" = g."Id" AND ult.rn = 1
    WHERE  g."Estado"          = 'ACTIVO'
      AND  g."EstadoOperacion" = 'OPERATIVA'
      AND  g."Capacidad"      >= v_CantidadCarga
      AND  g."FecVenSeg"      >= v_FechaServicio
      AND  NOT EXISTS (
               SELECT 1 FROM "Reserva" r3
               WHERE  r3."IdGrua"          = g."Id"
                 AND  r3."FechaServicio"    = v_FechaServicio
                 AND  r3."Id"             != _IdReserva
                 AND  r3."EstadoOperacion" != 'CANCELADO'
                 AND  r3."HoraInicio"      < v_HoraFin
                 AND  r3."HoraFin"         > v_HoraInicio
                 AND  r3."Estado"          = 'ACTIVO'
           );
END;
$$;

CREATE OR REPLACE FUNCTION fn_SugerirAsignacion_Operadores(_IdReserva INT)
RETURNS TABLE(
    "Id"          INT,
    "Nombres"     VARCHAR(100),
    "Apellidos"   VARCHAR(100),
    "UltLatitud"  VARCHAR(20),
    "UltLongitud" VARCHAR(20)
)
LANGUAGE plpgsql AS $$
DECLARE
    v_FechaServicio DATE;
    v_HoraInicio    TIME;
    v_HoraFin       TIME;
    v_NroDia        SMALLINT;
BEGIN
    SELECT r."FechaServicio",r."HoraInicio",r."HoraFin",
           (EXTRACT(DOW FROM r."FechaServicio")::INT + 1)::SMALLINT
    INTO   v_FechaServicio,v_HoraInicio,v_HoraFin,v_NroDia
    FROM   "Reserva" r WHERE r."Id" = _IdReserva;

    RETURN QUERY
    SELECT o."Id",u."Nombres",u."Apellidos",
           ult."CoordLatDestino",ult."CoordLonDestino"
    FROM "Operador" o
    INNER JOIN "Usuario" u ON u."Id" = o."IdUsuario"
    LEFT JOIN (
        SELECT r2."CoordLatDestino",r2."CoordLonDestino",r2."IdOperador",
               ROW_NUMBER() OVER (PARTITION BY r2."IdOperador" ORDER BY r2."HoraFin" DESC) AS rn
        FROM   "Reserva" r2
        WHERE  r2."EstadoOperacion" != 'CANCELADO'
          AND  r2."FechaServicio"    = v_FechaServicio
          AND  r2."HoraFin"         <= v_HoraInicio
          AND  r2."Estado"           = 'ACTIVO'
    ) ult ON ult."IdOperador" = o."Id" AND ult.rn = 1
    WHERE  o."Estado"    = 'ACTIVO'
      AND  o."FecVenLic" >= v_FechaServicio
      AND  EXISTS (
               SELECT 1 FROM "Disponibilidad" d
               WHERE  d."IdOperador"  = o."Id"
                 AND  d."NroDia"      = v_NroDia
                 AND  d."Estado"      = 'ACTIVO'
                 AND  d."HoraInicio" <= v_HoraInicio
                 AND  d."HoraFin"    >= v_HoraFin
           )
      AND  NOT EXISTS (
               SELECT 1 FROM "Reserva" r3
               WHERE  r3."IdOperador"      = o."Id"
                 AND  r3."FechaServicio"    = v_FechaServicio
                 AND  r3."Id"             != _IdReserva
                 AND  r3."EstadoOperacion" != 'CANCELADO'
                 AND  r3."HoraInicio"      < v_HoraFin
                 AND  r3."HoraFin"         > v_HoraInicio
                 AND  r3."Estado"          = 'ACTIVO'
           );
END;
$$;


